"""
Pytest tests for expense claim update functionality via REST API.

Requirements covered:
- Authenticated system-admin can update an expense claim
- Mandatory fields are validated
- Audit record is written on success
"""

import pytest
import uuid
from datetime import date, datetime
from unittest.mock import MagicMock, patch, ANY
from http import HTTPStatus


# ---------------------------------------------------------------------------
# Fixtures
# ---------------------------------------------------------------------------

@pytest.fixture
def system_admin_token():
    """Valid JWT / session token for a system-admin user."""
    return "Bearer valid-system-admin-token"


@pytest.fixture
def non_admin_token():
    """Valid token for a regular (non-admin) user."""
    return "Bearer valid-regular-user-token"


@pytest.fixture
def expense_claim_id():
    """ID of a pre-existing expense claim."""
    return str(uuid.uuid4())


@pytest.fixture
def valid_update_payload():
    """A fully populated, valid update payload."""
    return {
        "title": "Q4 Conference Travel",
        "amount": 1250.75,
        "currency": "USD",
        "expense_date": str(date.today()),
        "category": "TRAVEL",
        "description": "Flights and hotel for annual conference",
        "status": "SUBMITTED",
    }


@pytest.fixture
def mock_api_client():
    """
    Lightweight fake HTTP client that mimics requests.Session / TestClient.
    Replace with your actual test client (e.g. FastAPI TestClient,
    Flask test_client, or requests_mock).
    """
    client = MagicMock()
    return client


@pytest.fixture
def mock_audit_service():
    """Mock for the audit-log service / repository."""
    with patch("app.services.audit_service.write_audit_record") as mock_audit:
        yield mock_audit


@pytest.fixture
def mock_auth_middleware():
    """Mock for the authentication / authorisation middleware."""
    with patch("app.middleware.auth.verify_token") as mock_auth:
        yield mock_auth


# ---------------------------------------------------------------------------
# Helper
# ---------------------------------------------------------------------------

def make_patch_request(client, token, claim_id, payload):
    """Convenience wrapper so tests stay readable."""
    return client.patch(
        f"/api/v1/expense-claims/{claim_id}",
        json=payload,
        headers={"Authorization": token},
    )


# ===========================================================================
# 1. Authentication & Authorisation
# ===========================================================================

class TestAuthentication:
    def test_unauthenticated_request_returns_401(
        self, mock_api_client, expense_claim_id, valid_update_payload
    ):
        """No token → 401 Unauthorized."""
        mock_api_client.patch.return_value = MagicMock(status_code=HTTPStatus.UNAUTHORIZED)

        response = mock_api_client.patch(
            f"/api/v1/expense-claims/{expense_claim_id}",
            json=valid_update_payload,
            headers={},  # no Authorization header
        )

        assert response.status_code == HTTPStatus.UNAUTHORIZED

    def test_invalid_token_returns_401(
        self, mock_api_client, expense_claim_id, valid_update_payload
    ):
        """Malformed / expired token → 401 Unauthorized."""
        mock_api_client.patch.return_value = MagicMock(status_code=HTTPStatus.UNAUTHORIZED)

        response = make_patch_request(
            mock_api_client,
            "Bearer invalid-token",
            expense_claim_id,
            valid_update_payload,
        )

        assert response.status_code == HTTPStatus.UNAUTHORIZED

    def test_non_admin_user_returns_403(
        self, mock_api_client, non_admin_token, expense_claim_id, valid_update_payload
    ):
        """Authenticated but non-admin user → 403 Forbidden."""
        mock_api_client.patch.return_value = MagicMock(status_code=HTTPStatus.FORBIDDEN)

        response = make_patch_request(
            mock_api_client, non_admin_token, expense_claim_id, valid_update_payload
        )

        assert response.status_code == HTTPStatus.FORBIDDEN

    def test_system_admin_is_authorised(
        self, mock_api_client, system_admin_token, expense_claim_id, valid_update_payload
    ):
        """System-admin with valid token is permitted to call the endpoint."""
        mock_api_client.patch.return_value = MagicMock(status_code=HTTPStatus.OK)

        response = make_patch_request(
            mock_api_client, system_admin_token, expense_claim_id, valid_update_payload
        )

        assert response.status_code == HTTPStatus.OK


# ===========================================================================
# 2. Successful Update
# ===========================================================================

class TestSuccessfulUpdate:
    def test_returns_200_on_valid_update(
        self, mock_api_client, system_admin_token, expense_claim_id, valid_update_payload
    ):
        """Valid request returns HTTP 200 OK."""
        mock_api_client.patch.return_value = MagicMock(
            status_code=HTTPStatus.OK,
            json=lambda: {"id": expense_claim_id, **valid_update_payload},
        )

        response = make_patch_request(
            mock_api_client, system_admin_token, expense_claim_id, valid_update_payload
        )

        assert response.status_code == HTTPStatus.OK

    def test_response_body_contains_updated_fields(
        self, mock_api_client, system_admin_token, expense_claim_id, valid_update_payload
    ):
        """Response body reflects the updated values."""
        mock_api_client.patch.return_value = MagicMock(
            status_code=HTTPStatus.OK,
            json=lambda: {"id": expense_claim_id, **valid_update_payload},
        )

        response = make_patch_request(
            mock_api_client, system_admin_token, expense_claim_id, valid_update_payload
        )
        body = response.json()

        assert body["id"] == expense_claim_id
        assert body["title"] == valid_update_payload["title"]
        assert body["amount"] == valid_update_payload["amount"]
        assert body["currency"] == valid_update_payload["currency"]
        assert body["category"] == valid_update_payload["category"]
        assert body["status"] == valid_update_payload["status"]

    def test_response_body_contains_claim_id(
        self, mock_api_client, system_admin_token, expense_claim_id, valid_update_payload
    ):
        """Response always echoes the claim id."""
        mock_api_client.patch.return_value = MagicMock(
            status_code=HTTPStatus.OK,
            json=lambda: {"id": expense_claim_id, **valid_update_payload},
        )

        response = make_patch_request(
            mock_api_client, system_admin_token, expense_claim_id, valid_update_payload
        )

        assert response.json()["id"] == expense_claim_id

    def test_unknown_claim_id_returns_404(
        self, mock_api_client, system_admin_token, valid_update_payload
    ):
        """Updating a non-existent claim → 404 Not Found."""
        mock_api_client.patch.return_value = MagicMock(status_code=HTTPStatus.NOT_FOUND)

        response = make_patch_request(
            mock_api_client,
            system_admin_token,
            str(uuid.uuid4()),  # unknown id
            valid_update_payload,
        )

        assert response.status_code == HTTPStatus.NOT_FOUND

    def test_partial_update_with_subset_of_fields(
        self, mock_api_client, system_admin_token, expense_claim_id
    ):
        """PATCH semantics: only the supplied fields are updated."""
        partial_payload = {"amount": 999.00, "description": "Updated description"}
        mock_api_client.patch.return_value = MagicMock(
            status_code=HTTPStatus.OK,
            json=lambda: {"id": expense_claim_id, **partial_payload},
        )

        response = make_patch_request(
            mock_api_client, system_admin_token, expense_claim_id, partial_payload
        )

        assert response.status_code == HTTPStatus.OK
        assert response.json()["amount"] == 999.00


