class TestMandatoryFieldValidation:
    MANDATORY_FIELDS = ["title", "amount", "currency", "expense_date", "category"]

    @pytest.mark.parametrize("missing_field", MANDATORY_FIELDS)
    def test_missing_mandatory_field_returns_422(
        self,
        mock_api_client,
        system_admin_token,
        expense_claim_id,
        valid_update_payload,
        missing_field,
    ):
        """Each mandatory field, when absent, triggers HTTP 422 Unprocessable Entity."""
        payload = {k: v for k, v in valid_update_payload.items() if k != missing_field}
        mock_api_client.patch.return_value = MagicMock(
            status_code=HTTPStatus.UNPROCESSABLE_ENTITY,
            json=lambda: {"errors": [{"field": missing_field, "message": "required"}]},
        )

        response = make_patch_request(
            mock_api_client, system_admin_token, expense_claim_id, payload
        )

        assert response.status_code == HTTPStatus.UNPROCESSABLE_ENTITY

    @pytest.mark.parametrize("missing_field", MANDATORY_FIELDS)
    def test_missing_mandatory_field_error_references_field_name(
        self,
        mock_api_client,
        system_admin_token,
        expense_claim_id,
        valid_update_payload,
        missing_field,
    ):
        """Validation error response body identifies the missing field by name."""
        payload = {k: v for k, v in valid_update_payload.items() if k != missing_field}
        mock_api_client.patch.return_value = MagicMock(
            status_code=HTTPStatus.UNPROCESSABLE_ENTITY,
            json=lambda: {"errors": [{"field": missing_field, "message": "required"}]},
        )

        response = make_patch_request(
            mock_api_client, system_admin_token, expense_claim_id, payload
        )
        errors = response.json().get("errors", [])
        referenced_fields = [e["field"] for e in errors]

        assert missing_field in referenced_fields

    def test_null_mandatory_field_returns_422(
        self, mock_api_client, system_admin_token, expense_claim_id, valid_update_payload
    ):
        """Explicitly null value for a mandatory field is rejected."""
        payload = {**valid_update_payload, "amount": None}
        mock_api_client.patch.return_value = MagicMock(
            status_code=HTTPStatus.UNPROCESSABLE_ENTITY
        )

        response = make_patch_request(
            mock_api_client, system_admin_token, expense_claim_id, payload
        )

        assert response.status_code == HTTPStatus.UNPROCESSABLE_ENTITY

    def test_empty_string_mandatory_field_returns_422(
        self, mock_api_client, system_admin_token, expense_claim_id, valid_update_payload
    ):
        """Empty string for a mandatory text field is rejected."""
        payload = {**valid_update_payload, "title": ""}
        mock_api_client.patch.return_value = MagicMock(
            status_code=HTTPStatus.UNPROCESSABLE_ENTITY
        )

        response = make_patch_request(
            mock_api_client, system_admin_token, expense_claim_id, payload
        )

        assert response.status_code == HTTPStatus.UNPROCESSABLE_ENTITY

    def test_negative_amount_returns_422(
        self, mock_api_client, system_admin_token, expense_claim_id, valid_update_payload
    ):
        """Amount must be positive; negative value is rejected."""
        payload = {**valid_update_payload, "amount": -50.00}
        mock_api_client.patch.return_value = MagicMock(
            status_code=HTTPStatus.UNPROCESSABLE_ENTITY
        )

        response = make_patch_request(
            mock_api_client, system_admin_token, expense_claim_id, payload
        )

        assert response.status_code == HTTPStatus.UNPROCESSABLE_ENTITY

    def test_invalid_currency_code_returns_422(
        self, mock_api_client, system_admin_token, expense_claim_id, valid_update_payload
    ):
        """Currency must be a valid ISO-4217 code."""
        payload = {**valid_update_payload, "currency": "INVALID"}
        mock_api_client.patch.return_value = MagicMock(
            status_code=HTTPStatus.UNPROCESSABLE_ENTITY
        )

        response = make_patch_request(
            mock_api_client, system_admin_token, expense_claim_id, payload
        )

        assert response.status_code == HTTPStatus.UNPROCESSABLE_ENTITY

    def test_invalid_expense_date_format_returns_422(
        self, mock_api_client, system_admin_token, expense_claim_id, valid_update_payload
    ):
        """expense_date must conform to ISO-8601 (YYYY-MM-DD)."""
        payload = {**valid_update_payload, "expense_date": "31-12-2024"}
        mock_api_client.patch.return_value = MagicMock(
            status_code=HTTPStatus.UNPROCESSABLE_ENTITY
        )

        response = make_patch_request(
            mock_api_client, system_admin_token, expense_claim_id, payload
        )

        assert response.status_code == HTTPStatus.UNPROCESSABLE_ENTITY

    def test_invalid_category_value_returns_422(
        self, mock_api_client, system_admin_token, expense_claim_id, valid_update_payload
    ):
        """Category must be one of the allowed enum values."""
        payload = {**valid_update_payload, "category": "UNKNOWN_CATEGORY"}
        mock_api_client.patch.return_value = MagicMock(
            status_code=HTTPStatus.UNPROCESSABLE_ENTITY
        )

        response = make_patch_request(
            mock_api_client, system_admin_token, expense_claim_id, payload
        )

        assert response.status_code == HTTPStatus.UNPROCESSABLE_ENTITY

    def test_empty_request_body_returns_422(
        self, mock_api_client, system_admin_token, expense_claim_id
    ):
        """Empty JSON body is rejected because all mandatory fields are absent."""
        mock_api_client.patch.return_value = MagicMock(
            status_code=HTTPStatus.UNPROCESSABLE_ENTITY
        )

        response = make_patch_request(
            mock_api_client, system_admin_token, expense_claim_id, {}
        )

        assert response.status_code == HTTPStatus.UNPROCESSABLE_ENTITY


